#!/usr/bin/env node

import { Command } from 'commander';
import { resolveConfig } from './config.js';
import { registerStatusCommand } from './commands/status.js';

const __dirname = new URL('.', import.meta.url).pathname;
// Read version from package.json
let version = '0.1.0';
try {
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  const pkg = await import('../package.json', { with: { type: 'json' } });
  version = (pkg.default as Record<string, unknown>)?.version as string ?? version;
} catch {
  // fallback version
}

const program = new Command();

program
  .name('mt-cli')
  .description('Milestone Tracker AI Agent CLI — AI Agent 使用的里程碑跟踪命令行工具')
  .version(version, '-v, --version', '显示版本号')
  .option('--config <path>', '指定配置文件路径');

// Lazy config resolution — only resolve when a command needs it
function getConfig() {
  const opts = program.opts<{ config?: string }>();
  return resolveConfig(opts.config);
}

// Register commands
registerStatusCommand(program, getConfig);

// Parse and execute
program.parse(process.argv);

import { readFileSync, existsSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { homedir } from 'node:os';
import { fileURLToPath } from 'node:url';

// ── Types ───────────────────────────────────────────────────────────────────

export interface MtCliConfig {
  serverUrl: string;
  milestoneId: string;
  key?: string;
  agentName?: string;
}

export interface ResolvedConfig extends MtCliConfig {
  apiKey: string;
  configPath: string | null;
}

// ── Helpers ─────────────────────────────────────────────────────────────────

function readJsonFile(filePath: string): Record<string, unknown> | null {
  try {
    if (!existsSync(filePath)) return null;
    const raw = readFileSync(filePath, 'utf-8');
    return JSON.parse(raw) as Record<string, unknown>;
  } catch {
    console.error(`[警告] 配置文件解析失败: ${filePath}，已跳过`);
    return null;
  }
}

function readEnvFile(dir: string): string | null {
  const envPath = join(dir, '.mt-env');
  try {
    if (!existsSync(envPath)) return null;
    const raw = readFileSync(envPath, 'utf-8');
    for (const line of raw.split('\n')) {
      const trimmed = line.trim();
      if (trimmed.startsWith('MT_API_KEY=')) {
        return trimmed.slice('MT_API_KEY='.length).replace(/^["']|["']$/g, '');
      }
    }
    return null;
  } catch {
    return null;
  }
}

// ── Config Resolution ───────────────────────────────────────────────────────

/**
 * Resolve configuration with layered priority:
 * 1. Explicit --config path
 * 2. `.mt-cli.json` in cwd
 * 3. `~/.mt-cli.json` (home directory)
 *
 * API key priority:
 * 1. `MT_API_KEY` environment variable
 * 2. `.mt-env` file in cwd
 * 3. `key` field in config file
 */
export function resolveConfig(configPathOverride?: string): ResolvedConfig {
  let configData: Record<string, unknown> | null = null;
  let usedConfigPath: string | null = null;

  // 1. Try explicit config path
  if (configPathOverride) {
    configData = readJsonFile(configPathOverride);
    if (configData !== null) {
      usedConfigPath = configPathOverride;
    } else {
      console.error(`[错误] 指定的配置文件不存在或格式错误: ${configPathOverride}`);
      process.exit(1);
    }
  }

  // 2. Try cwd .mt-cli.json
  if (configData === null) {
    const cwdConfig = join(process.cwd(), '.mt-cli.json');
    const data = readJsonFile(cwdConfig);
    if (data !== null) {
      configData = data;
      usedConfigPath = cwdConfig;
    }
  }

  // 3. Try ~/.mt-cli.json
  if (configData === null) {
    const homeConfig = join(homedir(), '.mt-cli.json');
    const data = readJsonFile(homeConfig);
    if (data !== null) {
      configData = data;
      usedConfigPath = homeConfig;
    }
  }

  if (configData === null) {
    console.error(
      '[错误] 未找到配置文件。请在项目根目录创建 .mt-cli.json 或在 HOME 目录创建 ~/.mt-cli.json。'
    );
    console.error('[提示] 配置格式: { "serverUrl": "http://localhost:5173", "milestoneId": "MS-1" }');
    process.exit(1);
  }

  // Extract fields with defaults
  const serverUrl = (configData['serverUrl'] as string) || 'http://localhost:5173';
  const milestoneId = configData['milestoneId'] as string;
  const key = configData['key'] as string | undefined;
  const agentName = configData['agentName'] as string | undefined;

  if (!milestoneId) {
    console.error('[错误] 配置文件中缺少必填字段 "milestoneId"。');
    process.exit(1);
  }

  // API key resolution: env → .mt-env file → config key field
  const envKey = process.env['MT_API_KEY'] || null;
  const envFileKey = readEnvFile(process.cwd());
  const apiKey = envKey || envFileKey || key || '';

  if (!apiKey) {
    console.error(
      '[错误] 未找到 API 密钥。请设置环境变量 MT_API_KEY、创建 .mt-env 文件，或在配置文件中添加 "key" 字段。'
    );
    process.exit(1);
  }

  return {
    serverUrl,
    milestoneId,
    key,
    agentName,
    apiKey,
    configPath: usedConfigPath,
  };
}

// ── HTTP Error Messages (Chinese) ────────────────────────────────────────────

const STATUS_MESSAGES: Record<number, string> = {
  400: '请求格式错误，请检查请求参数',
  401: 'API 密钥无效或已过期，请检查 MT_API_KEY 或 .mt-env 配置',
  403: '无权限执行此操作',
  404: '请求的资源不存在，请检查 URL 和 ID',
  409: '操作冲突，资源状态已变更，请刷新后重试',
  422: '请求数据验证失败，请检查字段格式',
  429: '请求过于频繁，请稍后重试',
  500: '服务器内部错误，请联系管理员',
  502: '网关错误，服务器暂时不可用',
  503: '服务暂时不可用，请稍后重试',
};

function getStatusMessage(status: number): string {
  return STATUS_MESSAGES[status] || `未知错误 (HTTP ${status})`;
}

function getSuggestion(status: number): string {
  switch (status) {
    case 400:
    case 422:
      return '[建议] 检查请求参数是否符合 API 规范';
    case 401:
      return '[建议] 重新获取 API 密钥或检查 .mt-cli.json 中的 key 配置';
    case 404:
      return '[建议] 使用 mt-cli status 确认服务器地址和里程碑 ID';
    case 409:
      return '[建议] 先查询最新状态 (mt-cli list)，再尝试操作';
    default:
      return '[建议] 稍后重试，或使用 mt-cli status 检查服务器连通性';
  }
}

// ── Error Class ─────────────────────────────────────────────────────────────

export class MtCliError extends Error {
  constructor(
    public readonly status: number,
    public readonly message: string,
    public readonly suggestion: string,
    public readonly url: string,
  ) {
    super(`[错误] HTTP ${status}: ${message}\n${suggestion}`);
    this.name = 'MtCliError';
  }
}

// ── HTTP Client ─────────────────────────────────────────────────────────────

export interface MtClientOptions {
  baseUrl: string;
  apiKey: string;
  timeoutMs?: number;
}

export class MtClient {
  private baseUrl: string;
  private apiKey: string;
  private timeoutMs: number;

  constructor(opts: MtClientOptions) {
    this.baseUrl = opts.baseUrl.replace(/\/+$/, '');
    this.apiKey = opts.apiKey;
    this.timeoutMs = opts.timeoutMs ?? 10_000;
  }

  private headers(): Record<string, string> {
    return {
      'Authorization': `Bearer ${this.apiKey}`,
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    };
  }

  async get<T>(path: string): Promise<T> {
    return this.request<T>('GET', path);
  }

  async post<T>(path: string, body?: unknown): Promise<T> {
    return this.request<T>('POST', path, body);
  }

  async patch<T>(path: string, body?: unknown): Promise<T> {
    return this.request<T>('PATCH', path, body);
  }

  private async request<T>(method: string, path: string, body?: unknown): Promise<T> {
    const url = `${this.baseUrl}${path}`;
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), this.timeoutMs);

    try {
      const response = await fetch(url, {
        method,
        headers: this.headers(),
        body: body !== undefined ? JSON.stringify(body) : undefined,
        signal: controller.signal,
      });

      clearTimeout(timer);

      // Log request on failure
      if (!response.ok) {
        console.error(`[HTTP] ${method} ${url} → ${response.status}`);
      }

      let data: unknown;
      const text = await response.text();
      try {
        data = JSON.parse(text);
      } catch {
        // Non-JSON response
        if (!response.ok) {
          throw new MtCliError(
            response.status,
            `服务器返回非 JSON 响应: ${text.slice(0, 200)}`,
            getSuggestion(response.status),
            url,
          );
        }
        throw new Error(`[错误] 无法解析服务器响应为 JSON`);
      }

      if (!response.ok) {
        const errData = data as Record<string, unknown>;
        const message =
          (errData['message'] as string) ||
          (errData['error'] as string) ||
          getStatusMessage(response.status);
        throw new MtCliError(response.status, message, getSuggestion(response.status), url);
      }

      return data as T;
    } catch (err) {
      clearTimeout(timer);
      if (err instanceof MtCliError) throw err;
      if (err instanceof DOMException && err.name === 'AbortError') {
        throw new MtCliError(
          0,
          `请求超时 (${this.timeoutMs}ms)，服务器未响应`,
          '[建议] 检查服务器是否运行，或使用 mt-cli status 测试连通性',
          url,
        );
      }
      if (err instanceof TypeError && (err as Error).message.includes('fetch')) {
        throw new MtCliError(
          0,
          `无法连接到服务器: ${(err as Error).message}`,
          '[建议] 检查 serverUrl 配置和服务器运行状态',
          url,
        );
      }
      throw err;
    }
  }
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';

interface MilestoneResponse {
  id: string;
  title: string;
  status: string;
  [key: string]: unknown;
}

export function registerStatusCommand(program: Command, getConfig: () => ResolvedConfig): void {
  program
    .command('status')
    .description('检查服务器连通性和配置状态')
    .action(async () => {
      const config = getConfig();
      const client = new MtClient({
        baseUrl: config.serverUrl,
        apiKey: config.apiKey,
      });

      console.log('╔══════════════════════════════════════╗');
      console.log('║        mt-cli 状态诊断              ║');
      console.log('╚══════════════════════════════════════╝');
      console.log('');
      console.log(`  服务器地址:  ${config.serverUrl}`);
      console.log(`  里程碑 ID:   ${config.milestoneId}`);
      console.log(`  Agent 名称:  ${config.agentName || '(未设置)'}`);
      console.log(`  API 密钥:    ${config.apiKey.slice(0, 4)}${'•'.repeat(Math.max(0, config.apiKey.length - 4))}`);
      console.log(`  配置文件:    ${config.configPath || '(未找到)'}`);
      console.log('');

      // Test server connectivity by fetching the milestone
      try {
        console.log('  正在检查服务器连通性...');
        const milestone = await client.get<MilestoneResponse>(
          `/api/milestones/${encodeURIComponent(config.milestoneId)}`
        );

        console.log('  ✅ 服务器连接成功');
        console.log('');
        console.log(`  里程碑标题:  ${milestone.title}`);
        console.log(`  里程碑状态:  ${milestone.status}`);
        console.log('');
        console.log('[信息] 配置正常，可以开始使用 mt-cli。');
      } catch (err) {
        console.log('  ❌ 服务器连接失败');
        if (err instanceof Error) {
          console.log(`  ${err.message}`);
        }
        console.log('');
        console.log('[建议] 请检查:');
        console.log('  1. 服务器是否运行 (npm run dev)');
        console.log('  2. .mt-cli.json 中的 serverUrl 是否正确');
        console.log('  3. API 密钥是否有效');
        process.exit(1);
      }
    });
}

